it('clears previous stacked_row assignments', function()
    local hunks = parser.parse_hunks({
        '@@ -1,2 +1,2 @@',
        ' context',
    })

    hunks[1].stacked_row = 10
    parser.assign_stacked_rows(hunks, { 1 })
    assert.is_nil(hunks[1].stacked_row)
end)

